import React, { useState, useEffect } from 'react';
import { Screen } from './types';
import SplashScreen from './components/SplashScreen';
import PlayerScreen from './components/PlayerScreen';
import ScheduleScreen from './components/ScheduleScreen';
import SettingsScreen from './components/SettingsScreen';
import Navigation from './components/Navigation';

const App: React.FC = () => {
  const [currentScreen, setCurrentScreen] = useState<Screen>(Screen.SPLASH);
  const [isPlaying, setIsPlaying] = useState(false);
  const [isDarkMode, setIsDarkMode] = useState(true);

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [isDarkMode]);

  const renderScreen = () => {
    switch (currentScreen) {
      case Screen.SPLASH:
        return <SplashScreen onComplete={() => setCurrentScreen(Screen.PLAYER)} />;
      case Screen.PLAYER:
        return <PlayerScreen isPlaying={isPlaying} setIsPlaying={setIsPlaying} />;
      case Screen.SCHEDULE:
        return <ScheduleScreen />;
      case Screen.SETTINGS:
        return <SettingsScreen isDarkMode={isDarkMode} setIsDarkMode={setIsDarkMode} />;
      default:
        return <PlayerScreen isPlaying={isPlaying} setIsPlaying={setIsPlaying} />;
    }
  };

  return (
    <div className="flex flex-col h-screen overflow-hidden max-w-md mx-auto relative bg-background-light dark:bg-background-dark shadow-2xl">
      <main className="flex-grow overflow-y-auto no-scrollbar">
        {renderScreen()}
      </main>

      {currentScreen !== Screen.SPLASH && (
        <Navigation 
          currentScreen={currentScreen} 
          setCurrentScreen={setCurrentScreen} 
          isPlaying={isPlaying}
        />
      )}
    </div>
  );
};

export default App;

import React from 'react';
import { Screen } from '../types';
import { Home, Calendar, Heart, Settings, Play, Pause } from 'lucide-react';

interface NavigationProps {
  currentScreen: Screen;
  setCurrentScreen: (screen: Screen) => void;
  isPlaying: boolean;
}

const Navigation: React.FC<NavigationProps> = ({ currentScreen, setCurrentScreen, isPlaying }) => {
  const navItems = [
    { id: Screen.PLAYER, label: 'Direct', icon: Home },
    { id: Screen.SCHEDULE, label: 'Programme', icon: Calendar },
    { id: Screen.FAVORITES, label: 'Favoris', icon: Heart },
    { id: Screen.SETTINGS, label: 'Réglages', icon: Settings },
  ];

  return (
    <nav className="fixed bottom-0 left-0 right-0 max-w-md mx-auto bg-white/80 dark:bg-background-dark/80 backdrop-blur-lg border-t border-slate-200 dark:border-white/5 px-6 pt-3 pb-8 z-50">
      <div className="flex justify-between items-center relative">
        {navItems.map((item, index) => {
          const Icon = item.icon;
          const isActive = currentScreen === item.id;

          // Gap for the center play button
          if (index === 2) {
             return (
               <React.Fragment key="center-gap">
                <div className="w-12 h-12 -mt-10"></div>
                <button 
                  onClick={() => setCurrentScreen(item.id)}
                  className={`flex flex-col items-center gap-1 transition-colors ${isActive ? 'text-primary' : 'text-slate-400'}`}
                >
                  <Icon size={24} />
                  <span className="text-[10px] font-bold uppercase tracking-tight">{item.label}</span>
                </button>
               </React.Fragment>
             );
          }

          return (
            <button 
              key={item.id}
              onClick={() => setCurrentScreen(item.id)}
              className={`flex flex-col items-center gap-1 transition-colors ${isActive ? 'text-primary' : 'text-slate-400'}`}
            >
              <Icon size={24} />
              <span className="text-[10px] font-bold uppercase tracking-tight">{item.label}</span>
            </button>
          );
        })}

        {/* Floating Play Button */}
        <div className="absolute left-1/2 -translate-x-1/2 -top-12">
          <button 
            className="w-16 h-16 bg-primary rounded-full shadow-lg shadow-primary/40 flex items-center justify-center active:scale-95 transition-transform"
            onClick={() => setCurrentScreen(Screen.PLAYER)}
          >
            {isPlaying ? <Pause className="text-white fill-current" size={32} /> : <Play className="text-white fill-current translate-x-0.5" size={32} />}
          </button>
        </div>
      </div>
    </nav>
  );
};

